output_requirements.schema:
{
  "verdict": "ready | needs_work | blocked",
  "requirements_met": [
    {"requirement": "req 1", "status": "met | partial | unmet", "evidence": "how verified"}
  ],
  "test_coverage": "adequate | gaps | missing",
  "gaps": ["gap 1", "gap 2"],
  "blocking_issues": ["issue 1"],
  "recommendations": ["rec 1"],
  "pr_ready": true,
  "confidence": 8
}

